import React, { useState } from 'react';
import ProgressBar from '../components/ProgressBar';
import Options from '../components/Options';
import styles from '../styles/Survey.module.css'; // Import CSS module
import { useNavigate } from 'react-router-dom';
import avatarImage from '../assets/avatar.png'; // Avatar

const questions = [
  {
    question: "Bạn biết tới WellGreen từ đâu?",
    options: [
      "YouTube",
      "TV",
      "Bạn bè/gia đình",
      "Tìm kiếm Google",
      "Tin tức/báo chí/blog",
      "TikTok",
      "Facebook/Instagram",
      "Khác"
    ]
  }
];

const Survey = () => {
  const navigate = useNavigate();
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0); // Chỉ số câu hỏi hiện tại
  const [selectedOption, setSelectedOption] = useState(null); // Lựa chọn được chọn

  const handleNext = () => {
    if (currentQuestionIndex < questions.length - 1) {
      setCurrentQuestionIndex(currentQuestionIndex + 1); // Chuyển đến câu hỏi tiếp theo
      setSelectedOption(null); // Reset lựa chọn
    } else {
      navigate('/home'); // Chuyển hướng đến trang Home sau khi hoàn thành
    }
  };

  return (
    <div className={styles.surveyContainer}>
      <div className={styles.progressBar}>
        <div
          className={styles.progressBarFilled}
          style={{ width: `${((currentQuestionIndex + 1) / questions.length) * 100}%` }}
        ></div>
      </div>

      <img src={avatarImage} alt="Avatar" className={styles.avatar} />
      <div className={styles.questionBox}>
        {questions[currentQuestionIndex].question}
      </div>

      <Options
        options={questions[currentQuestionIndex].options}
        selectedOption={selectedOption}
        setSelectedOption={setSelectedOption}
      />

      <div className={styles.buttonContainer}>
        <button
          className={styles.continueButton}
          onClick={handleNext}
          disabled={selectedOption === null}
        >
          Tiếp tục
        </button>
      </div>
    </div>
  );
};

export default Survey;
